def assert_spirv_asm_validates_if_available(spv_code, tmp_path):
    spirv_as = shutil.which("spirv-as")
    spirv_val = shutil.which("spirv-val")
    if not spirv_as or not spirv_val:
        return

    asm_path = tmp_path / "shader.spvasm"
    spv_path = tmp_path / "shader.spv"
    asm_path.write_text(spv_code, encoding="utf-8")

    assemble = subprocess.run(
        [spirv_as, str(asm_path), "-o", str(spv_path)],
        capture_output=True,
        text=True,
        check=False,
    )
    assert assemble.returncode == 0, assemble.stderr

    validate = subprocess.run(
        [spirv_val, str(spv_path)],
        capture_output=True,
        text=True,
        check=False,
    )
    assert validate.returncode == 0, validate.stderr


def assert_metal_validates_if_available(metal_code, tmp_path):
    xcrun = shutil.which("xcrun")
    if not xcrun:
        return

    probe = subprocess.run(
        [xcrun, "-sdk", "macosx", "-f", "metal"],
        capture_output=True,
        text=True,
        check=False,
    )
    if probe.returncode != 0:
        return

    shader_path = tmp_path / "shader.metal"
    output_path = tmp_path / "shader.air"
    shader_path.write_text(metal_code, encoding="utf-8")

    compile_result = subprocess.run(
        [
            xcrun,
            "-sdk",
            "macosx",
            "metal",
            "-c",
            str(shader_path),
            "-o",
            str(output_path),
        ],
        capture_output=True,
        text=True,
        check=False,
    )
    assert compile_result.returncode == 0, compile_result.stderr


def assert_directx_vertex_validates_if_available(hlsl_code, tmp_path):
    dxc = shutil.which("dxc")
    if not dxc:
        return

    shader_path = tmp_path / "shader.hlsl"
    output_path = tmp_path / "shader.dxil"
    shader_path.write_text(hlsl_code, encoding="utf-8")

    compile_result = subprocess.run(
        [
            dxc,
            "-T",
            "vs_6_0",
            "-E",
            "VSMain",
            str(shader_path),
            "-Fo",
            str(output_path),
        ],
        capture_output=True,
        text=True,
        check=False,
    )
    assert compile_result.returncode == 0, compile_result.stdout + compile_result.stderr


