def assert_directx_compute_validates_if_available(hlsl_code, tmp_path):
    shader_path = tmp_path / "shader.hlsl"
    shader_path.write_text(hlsl_code, encoding="utf-8")

    glslang = shutil.which("glslangValidator")
    if glslang:
        output_path = tmp_path / "shader.spv"
        compile_result = subprocess.run(
            [
                glslang,
                "-D",
                "-V",
                "-S",
                "comp",
                "-e",
                "CSMain",
                str(shader_path),
                "-o",
                str(output_path),
            ],
            capture_output=True,
            text=True,
            check=False,
        )
        assert compile_result.returncode == 0, (
            compile_result.stdout + compile_result.stderr
        )
        return

    dxc = shutil.which("dxc")
    if not dxc:
        return

    output_path = tmp_path / "shader.dxil"
    compile_result = subprocess.run(
        [
            dxc,
            "-T",
            "cs_6_0",
            "-E",
            "CSMain",
            str(shader_path),
            "-Fo",
            str(output_path),
        ],
        capture_output=True,
        text=True,
        check=False,
    )
    assert compile_result.returncode == 0, compile_result.stdout + compile_result.stderr


