SIMPLE_CROSSL = textwrap.dedent("""
    shader RepoShader {
        struct VertexInput {
            vec3 position;
        }

        struct VertexOutput {
            vec4 position;
        }

        vertex {
            VertexOutput main(VertexInput input) {
                VertexOutput output;
                output.position = vec4(input.position, 1.0);
                return output;
            }
        }
    }
    """).strip()

DIRECTX_GRAPHICS_CROSSL = textwrap.dedent("""
    shader ProjectDirectXGraphics {
        struct VSInput {
            vec3 position @ POSITION;
            vec2 uv @ TEXCOORD0;
        };

        struct VSOutput {
            vec4 position @ gl_Position;
            vec2 uv @ TEXCOORD0;
        };

        vertex {
            VSOutput main(VSInput input) {
                VSOutput output;
                output.position = vec4(input.position, 1.0);
                output.uv = input.uv;
                return output;
            }
        }

        fragment {
            vec4 main(VSOutput input) @ gl_FragColor {
                return vec4(input.uv, 0.0, 1.0);
            }
        }
    }
    """).strip()

GLSL_FRAGMENT_INVOCATION_DENSITY_SOURCE = textwrap.dedent("""
    #version 450 core
    #extension GL_EXT_fragment_invocation_density : require
    layout(location = 0) out vec4 fragColor;

    void main() {
        float invocationArea = float(
            gl_FragSizeEXT.x * gl_FragSizeEXT.y
        );
        float h = (
            clamp(1.0 - 1.0 / invocationArea, 0.0, 1.0)
        ) / 1.35;
        fragColor = vec4(h);
    }
    """).strip()

GLSL_FRAGMENT_INVOCATION_DENSITY_HELPER_SOURCE = textwrap.dedent("""
    #version 450 core
    #extension GL_EXT_fragment_invocation_density : require
    layout(location = 0) out vec4 fragColor;

    vec4 FragmentDensityToColor() {
        float invocationArea = float(
            gl_FragSizeEXT.x * gl_FragSizeEXT.y
        );
        float h = (
            clamp(1.0 - 1.0 / invocationArea, 0.0, 1.0)
        ) / 1.35;
        return vec4(h, h, h, 1.0);
    }

    void main() {
        fragColor = FragmentDensityToColor();
    }
    """).strip()

GLSLANG_SPEC_CONSTANT_VERTEX_SOURCE = textwrap.dedent("""
    #version 400
    layout(constant_id = 16) const int arraySize = 5;
    in vec4 ucol[arraySize];
    layout(constant_id = 17) const bool spBool = true;
    layout(constant_id = 18) const float spFloat = 3.14;
    layout(constant_id = 19) const double spDouble = 3.1415926535897932384626433832795;
    layout(constant_id = 22) const uint scale = 2;
    layout(constant_id = 24) gl_MaxImageUnits;
    out vec4 color;
    out int size;

    void foo(vec4 p[arraySize]);

    void main() {
        color = ucol[2];
        size = arraySize;
        if (spBool)
            color *= scale;
        color += float(spDouble / spFloat);
        foo(ucol);
    }

    layout(constant_id = 116) const int dupArraySize = 12;
    in vec4 dupUcol[dupArraySize];
    layout(constant_id = 117) const bool spDupBool = true;
    layout(constant_id = 118) const float spDupFloat = 3.14;
    layout(constant_id = 119) const double spDupDouble = 3.1415926535897932384626433832795;
    layout(constant_id = 122) const uint dupScale = 2;

    void foo(vec4 p[arraySize]) {
        color += dupUcol[2];
        size += dupArraySize;
        if (spDupBool)
            color *= dupScale;
        color += float(spDupDouble / spDupFloat);
    }

    int builtin_spec_constant() {
        int result = gl_MaxImageUnits;
        return result;
    }
    """).strip()


class ProjectPathLike:
    def __init__(self, path):
        self.path = path

    def __fspath__(self):
        return os.fspath(self.path)


class ProjectBytesPathLike:
    def __init__(self, path):
        self.path = path

    def __fspath__(self):
        return os.fsencode(self.path)


