def test_translate_project_lowers_hlsl_texture_sampling_pair_to_graphics_targets(
    tmp_path,
):
    repo = tmp_path / "repo"
    shader_dir = repo / "gpu"
    shader_dir.mkdir(parents=True)
    (shader_dir / "hello_texture.hlsl").write_text(
        textwrap.dedent("""
            struct PSInput
            {
                float4 position : SV_POSITION;
                float2 uv : TEXCOORD;
            };

            Texture2D g_texture : register(t0);
            SamplerState g_sampler : register(s0);

            PSInput VSMain(float4 position : POSITION, float2 uv : TEXCOORD)
            {
                PSInput result;
                result.position = position;
                result.uv = uv;
                return result;
            }

            float4 PSMain(PSInput input) : SV_TARGET
            {
                return g_texture.Sample(g_sampler, input.uv);
            }
            """).strip(),
        encoding="utf-8",
    )
    (repo / "crosstl.toml").write_text(
        textwrap.dedent("""
            [project]
            source_roots = ["gpu"]
            include = ["gpu/*.hlsl"]
            targets = ["cgl", "opengl", "metal", "directx", "vulkan", "mojo"]
            output_dir = "translated"
            """).strip(),
        encoding="utf-8",
    )

    report = translate_project(load_project_config(repo))
    payload = report.to_json()

    cgl = (repo / "translated" / "cgl" / "gpu" / "hello_texture.cgl").read_text(
        encoding="utf-8"
    )
    opengl = (repo / "translated" / "opengl" / "gpu" / "hello_texture.glsl").read_text(
        encoding="utf-8"
    )
    metal = (repo / "translated" / "metal" / "gpu" / "hello_texture.metal").read_text(
        encoding="utf-8"
    )
    directx = (
        repo / "translated" / "directx" / "gpu" / "hello_texture.hlsl"
    ).read_text(encoding="utf-8")
    vulkan = (
        repo / "translated" / "vulkan" / "gpu" / "hello_texture.spvasm"
    ).read_text(encoding="utf-8")
    mojo = (repo / "translated" / "mojo" / "gpu" / "hello_texture.mojo").read_text(
        encoding="utf-8"
    )

    assert payload["summary"]["unitCount"] == 1
    assert payload["summary"]["translatedCount"] == 6
    assert payload["summary"]["failedCount"] == 0
    assert len(payload["artifacts"]) == 6

    assert "PSInput VSMain(vec4 position @ Position, vec2 uv @ TexCoord)" in cgl
    assert "vec4 PSMain(PSInput input) @ gl_FragColor @ stage_entry" in cgl
    assert "return texture(g_texture, g_sampler, input.uv);" in cgl

    assert "struct VSMain_Input" in metal
    assert "float4 position [[attribute(0)]];" in metal
    assert "float2 uv [[attribute(4)]];" in metal
    assert "VSMain_Input _crossglInput [[stage_in]]" in metal
    assert "float4 position = _crossglInput.position;" in metal
    assert "float2 uv = _crossglInput.uv;" in metal
    assert "fragment float4 PSMain(PSInput input [[stage_in]]" in metal
    assert "g_texture.sample(g_sampler, input.uv)" in metal
    assert "[[Position]]" not in metal
    assert "[[TexCoord]]" not in metal
    assert "fragment void fragment_main" not in metal

    assert "layout(location = 4) out vec2 out_uv;" in opengl
    assert "layout(location = 4) in vec2 in_out_uv;" in opengl
    assert "layout(location = 0) out vec4 fragColor;" in opengl
    assert "fragColor = texture(g_texture, in_out_uv);" in opengl
    assert "vec4 PSMain(PSInput input)" not in opengl
    assert "void main() {\n}" not in opengl
    assert "PSInput" not in opengl

    assert "float4 PSMain(PSInput input): SV_TARGET" in directx
    assert "g_texture.Sample(g_sampler, input.uv)" in directx
    assert "void PSMain_2()" not in directx

    assert "OpEntryPoint Fragment" in vulkan
    assert '"PSMain"' in vulkan
    assert "BuiltIn FragCoord" in vulkan
    assert "OpImageSampleImplicitLod" in vulkan
    assert "WARNING: SPIR-V builtin gl_Position" not in vulkan

    assert "# CrossGL resource bindings" in mojo
    assert "# CrossGL resource placeholders" not in mojo
    assert (
        "# CrossGL resource metadata: name=g_texture kind=texture set=0 "
        "binding=0 binding_source=explicit register=t0"
    ) in mojo
    assert (
        "# CrossGL resource metadata: name=g_sampler kind=sampler set=0 "
        "binding=0 binding_source=explicit register=s0"
    ) in mojo
    assert "var g_texture: Texture2D = Texture2D(0, 0)" in mojo
    assert "var g_sampler: Sampler = Sampler(0, 0)" in mojo
    assert "return sample_sampler(g_texture, g_sampler, input.uv)" in mojo
    assert not [
        diagnostic
        for diagnostic in payload["diagnostics"]
        if diagnostic["code"] == project_pipeline.GENERATED_PLACEHOLDER_DIAGNOSTIC_CODE
        and diagnostic.get("target") == "mojo"
        and diagnostic["location"]["file"] == "translated/mojo/gpu/hello_texture.mojo"
    ]

    assert_metal_validates_if_available(metal, tmp_path)
    assert_guarded_glsl_validates_if_available(opengl, tmp_path)
    assert_spirv_asm_validates_if_available(vulkan, tmp_path)


def test_translate_project_lowers_hlsl_struct_main_vsh_psh_pair_to_native_entries(
    tmp_path,
):
    repo = tmp_path / "repo"
    (repo / "cube.vsh").parent.mkdir(parents=True, exist_ok=True)
    (repo / "cube.vsh").write_text(
        textwrap.dedent("""
            cbuffer Constants
            {
                float4x4 g_WorldViewProj;
            };

            struct VSInput
            {
                float3 Pos   : ATTRIB0;
                float4 Color : ATTRIB1;
            };

            struct PSInput
            {
                float4 Pos   : SV_POSITION;
                float4 Color : COLOR0;
            };

            void main(in  VSInput VSIn,
                      out PSInput PSIn)
            {
                PSIn.Pos   = mul(float4(VSIn.Pos, 1.0), g_WorldViewProj);
                PSIn.Color = VSIn.Color;
            }
            """).strip(),
        encoding="utf-8",
    )
    (repo / "cube.psh").write_text(
        textwrap.dedent("""
            struct PSInput
            {
                float4 Pos   : SV_POSITION;
                float4 Color : COLOR0;
            };

            struct PSOutput
            {
                float4 Color : SV_TARGET;
            };

            void main(in  PSInput  PSIn,
                      out PSOutput PSOut)
            {
                float4 Color = PSIn.Color;
                PSOut.Color = Color;
            }
            """).strip(),
        encoding="utf-8",
    )
    (repo / "crosstl.toml").write_text(
        textwrap.dedent("""
            [project]
            source_roots = ["."]
            include = ["cube.vsh", "cube.psh"]
            targets = ["cgl", "opengl", "metal", "vulkan"]
            output_dir = "translated"

            [project.sources]
            "cube.vsh" = "directx"
            "cube.psh" = "directx"
            """).strip(),
        encoding="utf-8",
    )

    report = translate_project(load_project_config(repo))
    payload = report.to_json()

    vertex_cgl = (repo / "translated" / "cgl" / "cube.vsh.cgl").read_text(
        encoding="utf-8"
    )
    fragment_cgl = (repo / "translated" / "cgl" / "cube.psh.cgl").read_text(
        encoding="utf-8"
    )
    vertex_glsl = (repo / "translated" / "opengl" / "cube.vsh.glsl").read_text(
        encoding="utf-8"
    )
    fragment_glsl = (repo / "translated" / "opengl" / "cube.psh.glsl").read_text(
        encoding="utf-8"
    )
    vertex_metal = (repo / "translated" / "metal" / "cube.vsh.metal").read_text(
        encoding="utf-8"
    )
    fragment_metal = (repo / "translated" / "metal" / "cube.psh.metal").read_text(
        encoding="utf-8"
    )
    vertex_vulkan = (repo / "translated" / "vulkan" / "cube.vsh.spvasm").read_text(
        encoding="utf-8"
    )
    fragment_vulkan = (repo / "translated" / "vulkan" / "cube.psh.spvasm").read_text(
        encoding="utf-8"
    )

    assert payload["summary"]["unitCount"] == 2
    assert payload["summary"]["translatedCount"] == 8
    assert payload["summary"]["failedCount"] == 0
    assert payload["summary"]["diagnosticCounts"] == {
        "note": 0,
        "warning": 0,
        "error": 0,
    }
    assert len(payload["artifacts"]) == 8

    assert "vertex {" in vertex_cgl
    assert "fragment {" in fragment_cgl

    assert "void main()" in vertex_glsl
    assert "void main()" in fragment_glsl
    assert not re.search(r"void\s+main\s*\([^)]*\bVSInput\b", vertex_glsl)
    assert not re.search(r"void\s+main\s*\([^)]*\bPSInput\b", vertex_glsl)
    assert not re.search(r"void\s+main\s*\([^)]*\bPSInput\b", fragment_glsl)
    assert not re.search(r"void\s+main\s*\([^)]*\bPSOutput\b", fragment_glsl)
    assert vertex_glsl.splitlines().count("in vec4 VSIn_Color;") == 1
    assert vertex_glsl.splitlines().count("out vec4 PSIn_Color;") == 1
    assert fragment_glsl.splitlines().count("in vec4 PSIn_Color;") == 1
    assert "layout(location = 0) out vec4 fragColor;" in fragment_glsl
    assert "fragColor = Color;" in fragment_glsl

    assert "vertex vertex_main_Return vertex_main(" in vertex_metal
    assert "fragment fragment_main_Return fragment_main(" in fragment_metal
    assert "void main(" not in vertex_metal
    assert "void main(" not in fragment_metal
    assert "float3 VSIn_Pos [[attribute(0)]];" in vertex_metal
    assert "float4 VSIn_Color [[attribute(1)]];" in vertex_metal
    assert "vertex_main_Input _crossglInput [[stage_in]]" in vertex_metal
    assert "float4 PSIn_Color [[user(Color0)]];" in vertex_metal
    assert "fragment_main_Input _crossglInput [[stage_in]]" in fragment_metal
    assert "float4 PSOut_Color [[color(0)]];" in fragment_metal

    assert "OpEntryPoint Vertex" in vertex_vulkan
    assert "OpEntryPoint Fragment" in fragment_vulkan

    assert_glsl_stage_validates_if_available(vertex_glsl, tmp_path, "vert")
    assert_glsl_stage_validates_if_available(fragment_glsl, tmp_path, "frag")
    assert_metal_validates_if_available(vertex_metal, tmp_path)
    assert_metal_validates_if_available(fragment_metal, tmp_path)
    assert_spirv_asm_validates_if_available(vertex_vulkan, tmp_path)
    assert_spirv_asm_validates_if_available(fragment_vulkan, tmp_path)


def test_translate_project_hlsl_groupshared_scalar_lowers_to_metal_threadgroup(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "SplatGroupSharedScalar.hlsl").write_text(
        textwrap.dedent("""
            groupshared int a;
            [numthreads(64, 1, 1)]
            void main() {
              a = 123;
              int4 x = (a).xxxx;
            }
            """).strip(),
        encoding="utf-8",
    )
    (repo / "crosstl.toml").write_text(
        textwrap.dedent("""
            [project]
            source_roots = ["."]
            include = ["SplatGroupSharedScalar.hlsl"]
            targets = ["cgl", "metal", "vulkan"]
            output_dir = "crosstl-out"
            """).strip(),
        encoding="utf-8",
    )

    report = translate_project(
        load_project_config(repo),
        format_output=False,
        validate=True,
    )
    payload = report.to_json()
    artifacts_by_target = {
        artifact["target"]: artifact for artifact in payload["artifacts"]
    }
    metal = (repo / artifacts_by_target["metal"]["path"]).read_text(encoding="utf-8")

    assert payload["summary"]["translatedCount"] == 3
    assert payload["summary"]["failedCount"] == 0
    assert artifacts_by_target["metal"]["status"] == "translated"
    assert "constant int a = int(0)" not in metal
    assert "unsupported Metal program-scope groupshared" not in metal
    assert "threadgroup int a;" in metal
    assert metal.index("threadgroup int a;") > metal.index("kernel void kernel_main")
    assert metal.index("threadgroup int a;") < metal.index("a = 123;")
    assert "a = 123;" in metal
    assert "int4 x = int4(a);" in metal
    assert not any(
        diagnostic["code"] == project_pipeline.GENERATED_PLACEHOLDER_DIAGNOSTIC_CODE
        and diagnostic.get("target") == "metal"
        for diagnostic in payload["diagnostics"]
    )
    assert_metal_validates_if_available(metal, tmp_path)


