    cgl = (repo / "translated" / "cgl" / "gpu" / "headless.cgl").read_text(
        encoding="utf-8"
    )
    opengl = (repo / "translated" / "opengl" / "gpu" / "headless.glsl").read_text(
        encoding="utf-8"
    )
    directx = (repo / "translated" / "directx" / "gpu" / "headless.hlsl").read_text(
        encoding="utf-8"
    )
