    assert diagnostic["target"] == "opengl"
    assert diagnostic["sourceBackend"] == "metal"
    assert diagnostic["missingCapabilities"] == ["template.specialization"]
    assert (
        f"{expected_name} missing {', '.join(expected_missing)}"
        in diagnostic["message"]
    )


