        json.dumps(
            {
                "schemaVersion": 1,
                "kind": "crosstl-project-portability-report",
                "project": {
                    "root": str(repo),
                    "targets": ["opengl"],
                    "outputDir": "out",
                },
                "artifacts": [],
                "migration": {
                    "scope": "runtime-porting",
                    "nonGoals": "runtime migration",
                    "actionCount": "3",
                    "actionsByKind": [],
                    "actionsBySeverity": {"note": 2},
                    "actionsByTarget": {"opengl": 2},
                    "actions": [
                        {
                            "kind": "",
                            "severity": "fatal",
                            "message": "",
                            "targets": "opengl",
                        },
                        {
                            "kind": "runtime-porting",
                            "severity": "note",
                            "message": "Review host runtime integration.",
                            "targets": ["opengl"],
                        },
                        "not an action",
                    ],
                },
            }
        ),
