    assert (
        "migration.actions[0].runtimeReferences[0].line must be a positive integer"
        in diagnostic["message"]
    )
    assert (
        "migration.actions[0].runtimeReferences[0].column must be a positive integer"
        in diagnostic["message"]
    )
