def test_translate_project_directx_translates_mlx_steel_issue_943_frontier(
    tmp_path,
):
    repo = tmp_path / "repo"
    issue_paths = [
        "mlx/backend/metal/kernels/steel/attn/kernels/steel_attention_nax.metal",
        "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_fused.metal",
        "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_gather.metal",
        "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_masked.metal",
        "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_segmented.metal",
        "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_splitk.metal",
    ]
    for offset, relative_path in enumerate(issue_paths, start=1):
        source_path = repo / relative_path
        source_path.parent.mkdir(parents=True, exist_ok=True)
        source_path.write_text(
            textwrap.dedent(f"""
                #include <metal_stdlib>
                using namespace metal;

                #define instantiate_steel(name, itype, offset) \\
                    instantiate_kernel("issue943_" #name, steel_kernel, itype, offset)

                template <typename T>
                struct FragValue {{
                    T value;
                }};

                template <typename T>
                struct RecursiveTile {{
                    using NAXFrag_t = RecursiveTile<T>;

                    template <typename U>
                    using dtype_frag_t = FragValue<U>;
                }};

                template <typename T, typename NAXTile_t>
                struct TransformNone {{
                    using CFrag = typename NAXTile_t::NAXFrag_t;
                    using cfrag_t = typename CFrag::template dtype_frag_t<T>;

                    cfrag_t celems;
                }};

                inline float steel_dependent_value(float value) {{
                    TransformNone<float, RecursiveTile<float>> transform;
                    transform.celems.value = value;
                    return transform.celems.value;
                }}

                template <typename T, int Offset>
                [[kernel]] void steel_kernel(
                    device T* out [[buffer(0)]],
                    uint gid [[thread_position_in_grid]]) {{
                    T value = T(steel_dependent_value(float(gid + Offset)));
                    out[gid] = value;
                }}

                instantiate_steel(float32, float, {offset})
                """).strip() + "\n",
            encoding="utf-8",
        )

    (repo / "crosstl.toml").write_text(
        textwrap.dedent("""
            [project]
            source_roots = ["mlx/backend/metal/kernels/steel"]
            include = [
              "mlx/backend/metal/kernels/steel/attn/kernels/steel_attention_nax.metal",
              "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_fused.metal",
              "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_gather.metal",
              "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_masked.metal",
              "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_segmented.metal",
              "mlx/backend/metal/kernels/steel/gemm/kernels/steel_gemm_splitk.metal",
            ]
            targets = ["directx"]
            output_dir = "out"
            """).strip() + "\n",
        encoding="utf-8",
    )

    payload = translate_project(load_project_config(repo)).to_json()

    assert payload["summary"]["artifactCount"] == len(issue_paths)
    assert payload["summary"]["translatedCount"] == len(issue_paths)
    assert payload["summary"]["failedCount"] == 0
    assert payload["summary"]["diagnosticsByCode"] == {}
    assert payload["summary"]["missingCapabilityCounts"] == {}
    assert payload["summary"]["artifactsByTarget"] == {
        "directx": {
            "artifactCount": len(issue_paths),
            "translatedCount": len(issue_paths),
            "failedCount": 0,
        }
    }
    assert payload["summary"]["artifactsBySourceBackend"] == {
        "metal": {
            "artifactCount": len(issue_paths),
            "translatedCount": len(issue_paths),
            "failedCount": 0,
        }
    }
    assert payload["diagnostics"] == []

    translated_sources = {
        artifact["source"]
        for artifact in payload["artifacts"]
        if artifact["status"] == "translated"
    }
    assert translated_sources == set(issue_paths)
    for artifact in payload["artifacts"]:
        generated = (repo / artifact["path"]).read_text(encoding="utf-8")
        assert "struct RecursiveTile" in generated
        assert "float steel_dependent_value(float value)" in generated
        assert "RWStructuredBuffer<float> out_" in generated
        assert "SV_DispatchThreadID" in generated


def test_translate_project_models_glsl_fragment_invocation_density_by_target(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "CubeFDM_fs.glsl").write_text(
        GLSL_FRAGMENT_INVOCATION_DENSITY_SOURCE, encoding="utf-8"
    )

    report = translate_project(
        repo,
        targets=["metal", "directx", "vulkan", "opengl"],
        output_dir="out",
    )
    payload = report.to_json()
    report_path = repo / "fragment-density-report.json"
    report.write_json(report_path)
    validation = validate_project_report(report_path)

    assert "project.validate.invalid-report" not in validation["diagnosticsByCode"]
    assert payload["summary"]["artifactCount"] == 4
    assert payload["summary"]["translatedCount"] == 3
    assert payload["summary"]["failedCount"] == 1
    assert payload["summary"]["diagnosticsByCode"] == {
        "project.translate.unsupported-feature": 1
    }
    assert payload["summary"]["missingCapabilityCounts"] == {
        "glsl.builtin.gl_FragSizeEXT": 1,
        "glsl.extension.GL_EXT_fragment_invocation_density": 1,
    }
    assert payload["summary"]["diagnosticsByTarget"] == {
        "metal": 1,
    }

    diagnostics = payload["diagnostics"]
    assert len(diagnostics) == 1
    diagnostic = diagnostics[0]
    assert diagnostic["code"] == "project.translate.unsupported-feature"
    assert diagnostic["target"] == "metal"
    assert diagnostic["sourceBackend"] == "opengl"
    assert diagnostic["location"]["file"] == "CubeFDM_fs.glsl"
    assert "GL_EXT_fragment_invocation_density" in diagnostic["message"]
    assert "gl_FragSizeEXT" in diagnostic["message"]
    assert diagnostic["missingCapabilities"] == [
        "glsl.extension.GL_EXT_fragment_invocation_density",
        "glsl.builtin.gl_FragSizeEXT",
    ]

    required_capabilities = [
        "glsl.extension.GL_EXT_fragment_invocation_density",
        "glsl.builtin.gl_FragSizeEXT",
    ]
    artifacts_by_target = {
        artifact["target"]: artifact for artifact in payload["artifacts"]
    }
    assert set(artifacts_by_target) == {"metal", "directx", "vulkan", "opengl"}
    for artifact in artifacts_by_target.values():
        assert artifact["sourceBackend"] == "opengl"
        assert artifact["requiredCapabilities"] == required_capabilities

    metal_artifact = artifacts_by_target["metal"]
    assert metal_artifact["status"] == "failed"
    assert "GL_EXT_fragment_invocation_density" in metal_artifact["error"]
    assert "gl_FragSizeEXT" in metal_artifact["error"]
    assert "generatedHash" not in metal_artifact
    assert "generatedSizeBytes" not in metal_artifact
    assert not (repo / metal_artifact["path"]).exists()

    directx_code = (repo / artifacts_by_target["directx"]["path"]).read_text(
        encoding="utf-8"
    )
    assert artifacts_by_target["directx"]["status"] == "translated"
    assert "SV_ShadingRate" in directx_code
    assert "CrossGLFragmentSizeFromShadingRate" in directx_code
    assert "uint2 _crossglFragSize" in directx_code
    assert "GL_EXT_fragment_invocation_density" not in directx_code
    assert_directx_fragment_validates_if_available(directx_code, tmp_path)

    spirv_code = (repo / artifacts_by_target["vulkan"]["path"]).read_text(
        encoding="utf-8"
    )
