    assert host_interface["entryPoints"] == [
        {
            "name": "main",
            "stage": "compute",
            "executionConfig": {"local_size": [8, 2, 1]},
            "metadata": {"executionModel": "GLCompute", "function": "%main"},
        }
    ]
    assert host_interface["resources"][0] == {
        "name": "values",
        "kind": "buffer",
        "type": "Values",
        "set": 2,
        "binding": 3,
        "access": "read_write",
        "metadata": {
            "id": "%buf",
            "storageClass": "StorageBuffer",
            "typeId": "%ptr",
        },
    }
