def test_translate_project_opencl_targets_do_not_leak_resource_parameter_syntax(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "scale.cl").write_text(
        textwrap.dedent("""
            kernel void scale(global float *out,
                              global const float *in,
                              const float factor) {
                uint i = get_global_id(0);
                out[i] = in[i] * factor;
            }
            """).strip(),
        encoding="utf-8",
    )

    payload = translate_project(
        repo,
        targets=["opengl", "directx", "metal"],
        output_dir="out",
    ).to_json()

    assert {
        (artifact["target"], artifact["status"]) for artifact in payload["artifacts"]
    } == {
        ("opengl", "translated"),
        ("directx", "translated"),
        ("metal", "translated"),
    }

    outputs = {
        artifact["target"]: (repo / artifact["path"]).read_text(encoding="utf-8")
        for artifact in payload["artifacts"]
    }
    combined = "\n".join(outputs.values())

    assert "var<storage" not in combined
    assert "read_write>" not in combined
    assert ": group" not in combined
    assert "[[group]]" not in combined

    assert "layout(std430, binding = 0) buffer outBuffer { float out[]; };" in (
        outputs["opengl"]
    )
    assert "layout(std140, binding = 2) uniform scale_Args" in outputs["opengl"]
    assert "uint i = gl_GlobalInvocationID.x;" in outputs["opengl"]
    assert not re.search(r"\b(?:f32|u32)\b", outputs["opengl"])

    assert "RWStructuredBuffer<float> out : register(u0);" in outputs["directx"]
    assert "StructuredBuffer<float> in_ : register(t1);" in outputs["directx"]
    assert "RWStructuredBuffer<float> in_" not in outputs["directx"]
    assert "cbuffer scale_Args : register(b2)" in outputs["directx"]
    assert "[numthreads(1, 1, 1)]" in outputs["directx"]

    assert "device float* out [[buffer(0)]]" in outputs["metal"]
    assert "const device float* in_ [[buffer(1)]]" in outputs["metal"]
    assert "constant scale_Args& scale_Args [[buffer(2)]]" in outputs["metal"]
    assert "kernel void kernel_scale(" in outputs["metal"]


def test_translate_project_cuda_pointer_parameters_lower_to_opengl_buffers(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "vectorAdd.cu").write_text(
        textwrap.dedent("""
            extern "C" __global__ void vectorAdd(const float *A,
                                                  const float *B,
                                                  float *C,
                                                  int numElements) {
                int i = blockDim.x * blockIdx.x + threadIdx.x;
                if (i < numElements) {
                    C[i] = A[i] + B[i];
                }
            }
            """).strip(),
        encoding="utf-8",
    )

    payload = translate_project(
        repo,
        targets=["opengl"],
        output_dir="out",
    ).to_json()

    assert {
        (artifact["target"], artifact["status"]) for artifact in payload["artifacts"]
    } == {("opengl", "translated")}
    assert payload["summary"]["sourceRemapMappingCount"] == 6
    assert payload["artifacts"][0]["sourceRemap"]["mappingCount"] == 6

    output = (repo / payload["artifacts"][0]["path"]).read_text(encoding="utf-8")

    assert "layout(std430, binding = 0) buffer ABuffer { float A[]; };" in output
    assert "layout(std430, binding = 1) buffer BBuffer { float B[]; };" in output
    assert "layout(std430, binding = 2) buffer CBuffer { float C[]; };" in output
    assert "uniform vectorAdd_numElements_Args" in output
    assert "int vectorAdd_numElements_Args_numElements;" in output
    assert "if ((i < vectorAdd_numElements_Args_numElements))" in output
    assert not re.search(r"(?<!_)\bnumElements\b(?!_)", output)
    assert "void main()" in output
    assert "void vectorAdd(float A[]" not in output
    assert "float A[], float B[]" not in output

    assert_compute_glsl_validates_if_available(output, tmp_path)


