def test_translate_project_metal_matmul_unbound_device_buffers_lower_to_directx_resources(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "ShaderParams.h").write_text(
        textwrap.dedent("""
            #ifndef _SHADER_PARAMS_H
            #define _SHADER_PARAMS_H

            typedef struct
            {
                unsigned int row_dim_x;
                unsigned int col_dim_x;
                unsigned int inner_dim;
            } MatMulParams;

            #endif
            """).strip(),
        encoding="utf-8",
    )
    (repo / "mat_mul_simple1.metal").write_text(
        textwrap.dedent("""
            #include <metal_stdlib>
            #include "ShaderParams.h"
            using namespace metal;

            kernel void mat_mul_simple1(device const float* A,
                                        device const float* B,
                                        device float* X,
                                        constant MatMulParams& params,
                                        uint2 id [[ thread_position_in_grid ]])
            {
                const uint row_dim_x = params.row_dim_x;
                const uint col_dim_x = params.col_dim_x;
                const uint inner_dim = params.inner_dim;

                if ((id.x < col_dim_x) && (id.y < row_dim_x)) {
                    const uint index = id.y*col_dim_x + id.x;
                    float sum = 0;
                    for (uint k = 0; k < inner_dim; ++k) {
                        const uint index_A = id.y*inner_dim + k;
                        const uint index_B = k*col_dim_x + id.x;

                        sum += A[index_A] * B[index_B];
                    }
                    X[index] = sum;
                }
            }
            """).strip(),
        encoding="utf-8",
    )

    payload = translate_project(
        repo,
        targets=["directx"],
        output_dir="out",
    ).to_json()

    assert {
        (artifact["target"], artifact["status"]) for artifact in payload["artifacts"]
    } == {("directx", "translated")}

    output = (repo / payload["artifacts"][0]["path"]).read_text(encoding="utf-8")

    assert "StructuredBuffer<float> A : register(t0);" in output
    assert "StructuredBuffer<float> B : register(t1);" in output
    assert "RWStructuredBuffer<float> X : register(u2);" in output
    assert "ConstantBuffer<MatMulParams> params : register(b3);" in output
    assert "void CSMain(uint3 id_dispatchThreadID : SV_DispatchThreadID)" in output
    assert "uint2 id = id_dispatchThreadID.xy;" in output
    assert "A.Load(index_A)" in output
    assert "B.Load(index_B)" in output
    assert "X.Store(index, sum);" in output
    assert "float* A" not in output
    assert "float* B" not in output
    assert "float* X" not in output
    assert "void CSMain(float*" not in output
    assert_directx_compute_validates_if_available(output, tmp_path)


def test_translate_project_metal_matmul_uint2_grid_id_normalizes_for_compute_targets(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "matmul.metal").write_text(
        textwrap.dedent("""
            #include <metal_stdlib>
            using namespace metal;

            struct MatMulParams {
                uint row_dim_x;
                uint col_dim_x;
                uint inner_dim;
            };

            kernel void mat_mul_simple1(
                constant MatMulParams& params [[buffer(0)]],
                device const float* A [[buffer(1)]],
                device const float* B [[buffer(2)]],
                device float* X [[buffer(3)]],
                uint2 id [[thread_position_in_grid]]
            ) {
                uint row = id.y;
                uint col = id.x;
                float sum = 0.0;

                if (row < params.row_dim_x && col < params.col_dim_x) {
                    for (uint inner = 0; inner < params.inner_dim; inner++) {
                        uint index_A = (row * params.inner_dim) + inner;
                        uint index_B = (inner * params.col_dim_x) + col;
                        sum += A[index_A] * B[index_B];
                    }

                    uint index = (row * params.col_dim_x) + col;
                    X[index] = sum;
                }
            }
            """).strip(),
        encoding="utf-8",
    )

    payload = translate_project(
        repo,
        targets=["cuda", "hip", "mojo", "rust", "slang"],
        output_dir="out",
        validate=True,
    ).to_json()

    assert payload["summary"]["failedCount"] == 0
    assert payload["summary"]["diagnosticCounts"]["error"] == 0
    assert {
        (artifact["target"], artifact["status"]) for artifact in payload["artifacts"]
    } == {
        ("cuda", "translated"),
        ("hip", "translated"),
        ("mojo", "translated"),
        ("rust", "translated"),
        ("slang", "translated"),
    }

    outputs = {
        artifact["target"]: (repo / artifact["path"]).read_text(encoding="utf-8")
        for artifact in payload["artifacts"]
    }

    cuda = outputs["cuda"]
    assert (
        'extern "C" __global__ void mat_mul_simple1(const MatMulParams& params, '
        "const float* A, const float* B, float* X)"
    ) in cuda
    assert "uint row = (blockIdx.y * blockDim.y + threadIdx.y);" in cuda
    assert "uint col = (blockIdx.x * blockDim.x + threadIdx.x);" in cuda
    assert "uint2 id" not in cuda

    hip = outputs["hip"]
    assert (
        "__global__ void mat_mul_simple1(const MatMulParams& params, "
        "const float* A, const float* B, float* X)"
    ) in hip
    assert "unsigned int row = (blockIdx.y * blockDim.y + threadIdx.y);" in hip
    assert "unsigned int col = (blockIdx.x * blockDim.x + threadIdx.x);" in hip
    assert "uint2 id" not in hip

    mojo = outputs["mojo"]
    assert "id_globalInvocationID: SIMD[DType.uint32, 4]" in mojo
    assert (
        "var id: SIMD[DType.uint32, 2] = "
        "SIMD[DType.uint32, 2](id_globalInvocationID[0], "
        "id_globalInvocationID[1])"
    ) in mojo
    assert "var row: UInt32 = id[1]" in mojo
    assert "var col: UInt32 = id[0]" in mojo

    rust = outputs["rust"]
    assert "id_globalInvocationID: Vec3<u32>" in rust
    assert (
        "let id: Vec2<u32> = "
        "Vec2::<u32>::new(id_globalInvocationID.x, id_globalInvocationID.y);"
    ) in rust
    assert "let row: u32 = id.y;" in rust
    assert "let col: u32 = id.x;" in rust

    slang = outputs["slang"]
    assert "uint3 id_dispatchThreadID : SV_DispatchThreadID" in slang
    assert "uint2 id = id_dispatchThreadID.xy;" in slang
    assert "uint row = id.y;" in slang
    assert "uint col = id.x;" in slang

    for output in outputs.values():
        assert "thread_position_in_grid" not in output


