    payload = report.to_json()

    expected_materialization = {
        "status": "materialized",
        "specializationCount": 2,
        "configuredParameterCount": 0,
        "configuredParameters": {},
        "configuredParameterSources": {},
        "specializations": [
            {
                "name": "loop_kernel",
                "materializedName": "loop_float",
                "parameters": {"T": "float"},
                "parameterSources": {"T": "source-instantiation"},
                "source": "source-instantiation",
                "hostName": "loop_float",
            },
            {
                "name": "const_for_loop",
                "materializedName": "const_for_loop_0_4_1_float",
                "parameters": {
                    "F": "float",
                    "start": "0",
                    "step": "1",
                    "stop": "4",
                },
                "parameterSources": {
                    "F": "call-site",
                    "start": "call-site",
                    "step": "call-site",
                    "stop": "call-site",
                },
                "source": "call-site",
            },
        ],
        "unsupported": [],
    }

