def test_metal_project_materialization_concretizes_dispatch_bool_functor_helper(
    tmp_path,
):
    repo = tmp_path / "repo"
    shader_dir = repo / "shaders"
    shader_dir.mkdir(parents=True)
    source = textwrap.dedent("""
        #include <metal_stdlib>
        using namespace metal;

        #define instantiate_dispatch(name, type) \\
            instantiate_kernel("dispatch" #name, dispatch_kernel, type)

        template <typename T>
        struct WriteTrue {
            device T* out;
            uint gid;
            void operator()(bool value) const {
                out[gid] = value ? T(1) : T(0);
            }
        };

        template <typename F>
        METAL_FUNC void dispatch_bool(bool flag, F f) {
            f(flag);
        }

        template <typename T>
        [[kernel]] void dispatch_kernel(
            device T* out [[buffer(0)]],
            uint gid [[thread_position_in_grid]]
        ) {
            WriteTrue<T> writer{out, gid};
            dispatch_bool(true, writer);
        }

        instantiate_dispatch(_float, float)
        """).strip() + "\n"
    source_path = shader_dir / "dispatch_bool.metal"
    source_path.write_text(source, encoding="utf-8")
    unit = project_pipeline.ProjectTranslationUnit(
        path=source_path,
        relative_path="shaders/dispatch_bool.metal",
        source_backend="metal",
        extension=".metal",
        source_hash={"sha256": "test"},
        source_size_bytes=len(source.encode("utf-8")),
    )

    materialized = project_pipeline._project_template_materialization_for_artifact(
        unit=unit,
        target="opengl",
        variant=None,
        defines={},
        define_sources={},
        include_paths=[],
        source_options={},
    )

    assert materialized is not None
    assert list(materialized.diagnostics) == []
    assert materialized.metadata["status"] == "materialized"
    assert materialized.metadata["unsupported"] == []
    specializations = {
        record["name"]: record for record in materialized.metadata["specializations"]
    }
    assert specializations["dispatch_bool"] == {
        "name": "dispatch_bool",
        "materializedName": "dispatch_bool_WriteTrue_float",
        "parameters": {"F": "WriteTrue<float>"},
        "parameterSources": {"F": "call-site"},
        "source": "call-site",
    }
    assert "WriteTrue<float> writer{out, gid};" in materialized.text
    assert "dispatch_bool_WriteTrue_float(true, writer);" in materialized.text
    assert "dispatch_bool<" not in materialized.text


def test_translate_project_metal_multi_entry_instantiations_scope_vulkan_bindings(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "rope.metal").write_text(
        textwrap.dedent("""
            #include <metal_stdlib>
            using namespace metal;

            template <typename T, typename IdxT, int N = 4>
            T rope_impl(device const T* src, IdxT index) {
                return src[index] + T(N);
            }

            template <typename T, typename IdxT, int N = 4>
            [[kernel]] void rope(
                device const T* src [[buffer(0)]],
                device T* out [[buffer(1)]]
            ) {
                out[0] = rope_impl<T, IdxT, N>(src, IdxT(0));
            }

            template <typename T, typename IdxT, int N = 4>
            [[kernel]] void rope_freqs(
                device const T* src [[buffer(0)]],
                device T* out [[buffer(1)]]
            ) {
                out[0] = rope_impl<T, IdxT, N>(src, IdxT(0)) + T(1);
            }

            instantiate_kernel("rope_float32", rope, float, uint)
            instantiate_kernel("rope_freqs_float32", rope_freqs, float, uint)
            """).strip(),
        encoding="utf-8",
    )

    payload = translate_project(
        repo,
        targets=["opengl", "directx", "vulkan"],
        output_dir="out",
    ).to_json()

    assert payload["diagnostics"] == []
    assert payload["summary"]["translatedCount"] == 3
    assert payload["summary"]["failedCount"] == 0
    assert {
        (artifact["target"], artifact["status"]) for artifact in payload["artifacts"]
    } == {
        ("directx", "translated"),
        ("opengl", "translated"),
        ("vulkan", "translated"),
    }

    for artifact in payload["artifacts"]:
        materialization = artifact["templateMaterialization"]
        assert materialization["status"] == "materialized"
        assert materialization["unsupported"] == []
        assert {
            specialization["materializedName"]
            for specialization in materialization["specializations"]
        } == {
            "rope_float32",
            "rope_freqs_float32",
            "rope_impl_float_uint_4",
        }

    vulkan_artifact = next(
        artifact for artifact in payload["artifacts"] if artifact["target"] == "vulkan"
    )
    output = (repo / vulkan_artifact["path"]).read_text(encoding="utf-8")
    assert sorted(re.findall(r'OpEntryPoint GLCompute %\d+ "([^"]+)"', output)) == [
        "rope_float32",
        "rope_freqs_float32",
    ]
    assert len(re.findall(r"OpDecorate %\d+ Binding 0\b", output)) == 2
    assert len(re.findall(r"OpDecorate %\d+ Binding 1\b", output)) == 2
    assert "Duplicate SPIR-V resource binding" not in output
    assert_spirv_asm_validates_if_available(output, tmp_path)


