def test_translate_project_khronos_opencl_reduce_lowers_all_target_artifacts(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "reduce.cl").write_text(
        textwrap.dedent("""
            int op(int lhs, int rhs);
            int work_group_reduce_op(int val);
            int sub_group_reduce_op(int val);

            int read_local(local int* shared, size_t count, int zero, size_t i) {
                return i < count ? shared[i] : zero;
            }

            size_t zmin(size_t a, size_t b) {
                return a < b ? a : b;
            }

            kernel void reduce(
                global int* front,
                global int* back,
                local int* shared,
                unsigned long length,
                int zero_elem
            ) {
                const size_t lid = get_local_id(0),
                             lsi = get_local_size(0),
                             wid = get_group_id(0),
                             wsi = get_num_groups(0);
                const size_t wg_stride = lsi * 2,
                             valid_count = zmin(
                                 wg_stride,
                                 (size_t)(length) - wid * wg_stride
                             );

                event_t read;
                async_work_group_copy(
                    shared,
                    front + wid * wg_stride,
                    valid_count,
                    read
                );
                wait_group_events(1, &read);
                barrier(CLK_LOCAL_MEM_FENCE);

                #ifdef USE_WORK_GROUP_REDUCE
                int temp = work_group_reduce_op(
                    op(
                        read_local(shared, valid_count, zero_elem, lid),
                        read_local(shared, valid_count, zero_elem, lid + lsi)
                    )
                );
                if (lid == 0) back[wid] = temp;
                #else
                #ifdef USE_SUB_GROUP_REDUCE
                const uint sid = get_sub_group_id();
                const uint ssi = get_sub_group_size();
                const uint slid = get_sub_group_local_id();

                for (int i = valid_count ; i != 0 ; i /= ssi * 2) {
                    int temp = zero_elem;
                    if (sid * ssi < valid_count) {
                        temp = sub_group_reduce_op(
                            op(
                                read_local(
                                    shared,
                                    i,
                                    zero_elem,
                                    sid * 2 * ssi + slid
                                ),
                                read_local(
                                    shared,
                                    i,
                                    zero_elem,
                                    sid * 2 * ssi + slid + ssi
                                )
                            )
                        );
                    }
                    barrier(CLK_LOCAL_MEM_FENCE);
                    if (sid * ssi < valid_count) shared[sid] = temp;
                    barrier(CLK_LOCAL_MEM_FENCE);
                }
                if (lid == 0) back[wid] = shared[0];
                #else
                for (int i = lsi; i != 0; i /= 2) {
                    if (lid < i) {
                        shared[lid] = op(
                            read_local(shared, valid_count, zero_elem, lid),
                            read_local(shared, valid_count, zero_elem, lid + i)
                        );
                    }
                    barrier(CLK_LOCAL_MEM_FENCE);
                }
                if (lid == 0) back[wid] = shared[0];
                #endif
                #endif
            }
            """).strip(),
        encoding="utf-8",
    )

    payload = translate_project(
        repo,
        targets=["cgl", "opengl", "metal", "vulkan"],
        output_dir="out",
        validate=True,
    ).to_json()

    assert {
        (artifact["target"], artifact["status"]) for artifact in payload["artifacts"]
    } == {
        ("cgl", "translated"),
        ("opengl", "translated"),
        ("metal", "translated"),
        ("vulkan", "translated"),
    }
    assert payload["summary"]["translatedCount"] == 4
    assert payload["summary"]["failedCount"] == 0
    assert_only_optional_project_toolchain_warnings(payload)

    artifacts = {artifact["target"]: artifact for artifact in payload["artifacts"]}

    for target in ("cgl", "opengl", "metal", "vulkan"):
        assert (repo / artifacts[target]["path"]).exists()

    cgl_source = (repo / artifacts["cgl"]["path"]).read_text(encoding="utf-8")
    cgl_spec = SOURCE_REGISTRY.get("cgl")
    assert cgl_spec is not None
    cgl_spec.parse(cgl_source)
    assert "i32 op(i32 lhs, i32 rhs)" in cgl_source
    assert "return min(lhs, rhs);" in cgl_source
    assert "i32 read_local(array<i32, 1024> shared_" in cgl_source
    assert "shared_[lid] = front[((wid * wg_stride) + lid)];" in cgl_source
    assert "async_work_group_copy" not in cgl_source
    assert "wait_group_events" not in cgl_source
    assert "var read:" not in cgl_source
    assert "ptr<i32> shared_" not in cgl_source

    opengl_source = (repo / artifacts["opengl"]["path"]).read_text(encoding="utf-8")
    assert "int op(int lhs, int rhs)" in opengl_source
    assert "return min(lhs, rhs);" in opengl_source
    assert "shared int shared_[1024];" in opengl_source
    assert (
        "int read_local(int shared_[1024], uint count, int zero, uint i)"
        in opengl_source
    )
    assert "async_work_group_copy" not in opengl_source
    assert "wait_group_events" not in opengl_source
    assert "uint read;" not in opengl_source
    assert "ptr<i32>" not in opengl_source

    metal_source = (repo / artifacts["metal"]["path"]).read_text(encoding="utf-8")
    assert "int op(int lhs, int rhs)" in metal_source
    assert "return min(lhs, rhs);" in metal_source
    assert "threadgroup int shared_[1024];" in metal_source
    assert "int read_local(threadgroup int shared_[1024]" in metal_source
    assert "async_work_group_copy" not in metal_source
    assert "wait_group_events" not in metal_source
    assert "u64 read;" not in metal_source

    vulkan_source = (repo / artifacts["vulkan"]["path"]).read_text(encoding="utf-8")
    assert "async_work_group_copy" not in vulkan_source
    assert "wait_group_events" not in vulkan_source
    assert '"read"' not in vulkan_source

    for artifact in payload["artifacts"]:
        assert artifact["generatedHash"]["algorithm"] == "sha256"
        assert artifact["generatedSizeBytes"] > 0


