def test_translate_project_opencl_non_reduce_event_copy_reports_cgl_contract(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "copy.cl").write_text(
        textwrap.dedent("""
            kernel void copy_local(
                global int* front,
                global int* back,
                local int* shared
            ) {
                size_t lid = get_local_id(0);
                event_t read;
                async_work_group_copy(shared, front, 1, read);
                wait_group_events(1, &read);
                barrier(CLK_LOCAL_MEM_FENCE);
                back[lid] = shared[lid];
            }
            """).strip(),
        encoding="utf-8",
    )

    payload = translate_project(repo, targets=["cgl"], output_dir="out").to_json()

    artifact = payload["artifacts"][0]
    assert artifact["status"] == "failed"
    assert not (repo / artifact["path"]).exists()
    assert "async_work_group_copy, wait_group_events" in artifact["error"]
    assert payload["diagnosticCounts"] == {"note": 0, "warning": 0, "error": 2}
    assert payload["summary"]["diagnosticsByCode"] == {
        "opencl.target.unsupported-builtin": 2
    }
    assert payload["summary"]["diagnosticsByTarget"] == {"cgl": 2}

    messages = [diagnostic["message"] for diagnostic in payload["diagnostics"]]
    assert any("async_work_group_copy(...)" in message for message in messages)
    assert any("wait_group_events(...)" in message for message in messages)
    for diagnostic in payload["diagnostics"]:
        assert diagnostic["sourceBackend"] == "opencl"
        assert diagnostic["target"] == "cgl"
        assert diagnostic["location"]["file"] == "copy.cl"
        assert diagnostic["missingCapabilities"] == ["opencl.event-local-memory"]
        assert "Suggested action:" in diagnostic["message"]


def test_translate_project_mojo_vector_add_launch_separates_host_runtime(
    tmp_path,
):
    repo = tmp_path / "repo"
    repo.mkdir()
    (repo / "vector_addition.mojo").write_text(
        textwrap.dedent("""
            from std.sys import has_accelerator
            from std.gpu.host import DeviceContext
            from std.gpu import block_dim, block_idx, thread_idx
            from layout import TileTensor, row_major

            comptime float_dtype = DType.float32
            comptime vector_size = 4
            comptime layout = row_major[vector_size]()
            comptime block_size = 256
            comptime num_blocks = 1

            def vector_addition(
                lhs_tensor: TileTensor[float_dtype, type_of(layout), MutAnyOrigin],
                rhs_tensor: TileTensor[float_dtype, type_of(layout), MutAnyOrigin],
                out_tensor: TileTensor[float_dtype, type_of(layout), MutAnyOrigin],
            ):
                var tid = block_idx.x * block_dim.x + thread_idx.x
                if tid < vector_size:
                    out_tensor[tid] = lhs_tensor[tid] + rhs_tensor[tid]

            def main() raises:
                if not has_accelerator():
                    print("No compatible GPU found")
                else:
                    ctx = DeviceContext()
                    lhs = TileTensor(
                        ctx.enqueue_create_buffer[float_dtype](vector_size),
                        layout,
                    )
                    rhs = TileTensor(
                        ctx.enqueue_create_buffer[float_dtype](vector_size),
                        layout,
                    )
                    out = TileTensor(
                        ctx.enqueue_create_buffer[float_dtype](vector_size),
                        layout,
                    )
                    ctx.enqueue_function[vector_addition](
                        lhs,
                        rhs,
                        out,
                        grid_dim=num_blocks,
                        block_dim=block_size,
                    )
            """).strip(),
        encoding="utf-8",
    )

    payload = translate_project(
        repo,
        targets=["cgl", "metal", "vulkan"],
        output_dir="out",
    ).to_json()

    assert payload["diagnosticCounts"]["error"] == 0
    assert {
        (artifact["target"], artifact["status"]) for artifact in payload["artifacts"]
    } == {
        ("cgl", "translated"),
        ("metal", "translated"),
        ("vulkan", "translated"),
    }

    outputs = {
        artifact["target"]: (repo / artifact["path"]).read_text(encoding="utf-8")
        for artifact in payload["artifacts"]
    }
    for target in ("cgl", "metal", "vulkan"):
        assert "DType" not in outputs[target]
        assert "has_accelerator" not in outputs[target]
        assert "print(" not in outputs[target]
        assert "No compatible GPU found" not in outputs[target]

    assert "compute {" in outputs["cgl"]
    assert "kernel void vector_addition(" in outputs["metal"]
    assert "void main()" not in outputs["metal"]
    assert "OpEntryPoint GLCompute" in outputs["vulkan"]
    assert_spirv_asm_validates_if_available(outputs["vulkan"], tmp_path)
    assert_metal_validates_if_available(outputs["metal"], tmp_path)


